import React, { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../context/AuthContext';
import { api } from '../services/api';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';

// Corregir iconos de Leaflet en React
import icon from 'leaflet/dist/images/marker-icon.png';
import iconShadow from 'leaflet/dist/images/marker-shadow.png';

let DefaultIcon = L.icon({
    iconUrl: icon,
    shadowUrl: iconShadow,
    iconSize: [25, 41],
    iconAnchor: [12, 41]
});
L.Marker.prototype.options.icon = DefaultIcon;

const GestionLocales = () => {
    const { user } = useAuth();
    const [locales, setLocales] = useState([]);
    const [nuevoLocal, setNuevoLocal] = useState({
        nombre: '',
        direccion: '',
        ciudad: '',
        lat: -26.8083, 
        lng: -65.2176
    });

    const cargarLocales = useCallback(async () => {
        try {
            const idVendedor = user?.id || user?._id;
            if (idVendedor) {
                const data = await api.getLocalesVendedor(idVendedor);
                setLocales(data);
            }
        } catch (error) {
            console.error("Error cargando locales:", error);
        }
    }, [user]);

    useEffect(() => {
        cargarLocales();
    }, [cargarLocales]);

    // Manejador de clics en el mapa
    const LocationMarker = () => {
        useMapEvents({
            click(e) {
                setNuevoLocal(prev => ({
                    ...prev,
                    lat: e.latlng.lat,
                    lng: e.latlng.lng
                }));
            },
        });
        return <Marker position={[nuevoLocal.lat, nuevoLocal.lng]} />;
    };

    const handleCrearLocal = async (e) => {
        e.preventDefault();
        
        const idUsuario = user?.id || user?._id;
        
        if (!idUsuario) {
            alert("Sesión no válida");
            return;
        }

        const payload = {
            nombre: nuevoLocal.nombre,
            direccion: nuevoLocal.direccion,
            ciudad: nuevoLocal.ciudad,
            vendedorId: idUsuario,
            lat: nuevoLocal.lat,
            lng: nuevoLocal.lng
        };

        try {
            console.log("Enviando a la nube:", payload);
            await api.crearLocal(payload);
            alert("¡Local guardado exitosamente con ubicación GPS!");
            
            // Limpiar formulario
            setNuevoLocal({ 
                nombre: '', 
                direccion: '', 
                ciudad: '', 
                lat: -26.8083, 
                lng: -65.2176 
            });
            
            cargarLocales();
        } catch (error) {
            console.error("Error al crear local:", error);
            alert("Error al guardar local. Revisa la consola.");
        }
    };

    const handleEliminar = async (id) => {
        if (window.confirm("¿Estás seguro? Se borrarán también todas las ofertas de este local.")) {
            try {
                await api.eliminarLocal(id);
                cargarLocales();
            } catch (error) {
                alert("No se pudo eliminar el local");
            }
        }
    };

    return (
        <div style={{ padding: '20px', maxWidth: '1200px', margin: '0 auto', fontFamily: 'sans-serif' }}>
            <h2 style={{ color: '#1e293b' }}>Panel de Control: Mis Locales</h2>
            
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '25px', marginBottom: '40px' }}>
                {/* FORMULARIO */}
                <form onSubmit={handleCrearLocal} style={{ background: '#fff', padding: '25px', borderRadius: '12px', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}>
                    <h3 style={{ marginTop: 0 }}>Nuevo Punto de Venta</h3>
                    <div style={{ marginBottom: '15px' }}>
                        <label style={{ display: 'block', marginBottom: '5px', fontSize: '0.9rem' }}>Nombre del Local</label>
                        <input 
                            type="text" 
                            placeholder="Ej: Super Chinos" 
                            value={nuevoLocal.nombre}
                            onChange={(e) => setNuevoLocal({...nuevoLocal, nombre: e.target.value})}
                            style={{ width: '100%', padding: '10px', borderRadius: '6px', border: '1px solid #cbd5e1' }}
                            required 
                        />
                    </div>
                    <div style={{ marginBottom: '15px' }}>
                        <label style={{ display: 'block', marginBottom: '5px', fontSize: '0.9rem' }}>Dirección</label>
                        <input 
                            type="text" 
                            placeholder="Av. Alem 230" 
                            value={nuevoLocal.direccion}
                            onChange={(e) => setNuevoLocal({...nuevoLocal, direccion: e.target.value})}
                            style={{ width: '100%', padding: '10px', borderRadius: '6px', border: '1px solid #cbd5e1' }}
                            required 
                        />
                    </div>
                    
                    <div style={{ padding: '15px', background: '#f0f9ff', borderRadius: '8px', marginBottom: '15px', border: '1px solid #bae6fd' }}>
                        <p style={{ margin: '0 0 5px 0', fontSize: '0.9rem', color: '#0369a1', fontWeight: 'bold' }}>Coordenadas capturadas:</p>
                        <code style={{ fontSize: '0.85rem' }}>LAT: {nuevoLocal.lat}</code><br/>
                        <code style={{ fontSize: '0.85rem' }}>LNG: {nuevoLocal.lng}</code>
                        <p style={{ margin: '5px 0 0 0', fontSize: '0.75rem', color: '#0c4a6e' }}>* Haz clic en el mapa para actualizar la posición.</p>
                    </div>

                    <button type="submit" style={{ width: '100%', padding: '12px', background: '#2563eb', color: 'white', border: 'none', borderRadius: '6px', fontWeight: 'bold', cursor: 'pointer' }}>
                        Guardar Local con Ubicación
                    </button>
                </form>

                {/* MAPA */}
                <div style={{ height: '420px', borderRadius: '12px', overflow: 'hidden', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)', border: '1px solid #e2e8f0' }}>
                    <MapContainer center={[nuevoLocal.lat, nuevoLocal.lng]} zoom={14} style={{ height: '100%', width: '100%' }}>
                        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
                        <LocationMarker />
                    </MapContainer>
                </div>
            </div>

            <hr style={{ border: '0', borderTop: '1px solid #e2e8f0', margin: '40px 0' }} />

            <h3>Mis Locales Registrados</h3>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '20px' }}>
                {locales.map(local => (
                    <div key={local._id} style={{ background: '#fff', padding: '20px', borderRadius: '12px', borderLeft: '6px solid #2563eb', boxShadow: '0 1px 3px 0 rgb(0 0 0 / 0.1)' }}>
                        <h4 style={{ margin: '0 0 5px 0' }}>{local.nombre}</h4>
                        <p style={{ margin: '0 0 10px 0', color: '#64748b', fontSize: '0.85rem' }}>{local.direccion}</p>
                        <p style={{ fontSize: '0.75rem', color: '#94a3b8' }}>
                            📍 {local.location?.coordinates[1]}, {local.location?.coordinates[0]}
                        </p>
                        <div style={{ display: 'flex', gap: '10px', marginTop: '15px' }}>
                            <button 
                                onClick={() => window.location.href = `/gestion-ofertas/${local._id}`}
                                style={{ flex: 1, padding: '8px', background: '#10b981', color: 'white', border: 'none', borderRadius: '6px', cursor: 'pointer' }}
                            >
                                Gestionar Ofertas
                            </button>
                            <button 
                                onClick={() => handleEliminar(local._id)}
                                style={{ padding: '8px 12px', background: '#fee2e2', color: '#ef4444', border: 'none', borderRadius: '6px', cursor: 'pointer' }}
                            >
                                🗑️
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default GestionLocales;
